import DOFBaseLayer from '../bases/DOFBaseLayer';       

const GlowInfo = {
    layerType: "Glow",
    properties: {
        Enabled: {
            type: "bool",
            defaultValue: true,
            blendOperation: "lastOneWins"
        },
        Amount: {
            type: "float",
            defaultValue: 0.0,
            blendOperation: "add"
        },
        Blur: {
            type: "float",
            defaultValue: 15.0,
            blendOperation: "add"        
        },      
        HaloMaxDistance: {
            type: "float",
            defaultValue: 80,
            blendOperation: "add"        
        },       
        Halo: {
            type: "float",
            defaultValue: 0,
            blendOperation: "add"
        },
        Color: {
            type: "rgb",
            defaultValue: {
                r: 125,
                g: 249,
                b: 255
            },
            blendOperation: "add"
        }     
    }
};


export default class GlowLayer extends DOFBaseLayer {

    static generateDofs(props){
        return {
            glow_amount: !props.Enabled ? 0 : props.Amount,
            glow_blur: props.Blur,
            glow_halo: props.Halo,
            glow_haloMaxDistance: props.HaloMaxDistance,
            glow_redChannel: props.Color.r,
            glow_greenChannel: props.Color.g,
            glow_blueChannel: props.Color.b
        };
    }

    static getInfo() {
        return GlowInfo;
    }
} 
